CREATE TYPE "AccountTransactionDirection" AS ENUM ('DEBIT','CREDIT');
CREATE TABLE "PaymentAccount" ("id" TEXT NOT NULL,"name" TEXT NOT NULL,"accountType" TEXT NOT NULL,"accountNumber" TEXT,"description" TEXT,"initialBalance" DECIMAL(12,2) NOT NULL DEFAULT 0,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdBy" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "PaymentAccount_pkey" PRIMARY KEY("id"));
CREATE TABLE "AccountTransaction" ("id" TEXT NOT NULL,"accountId" TEXT NOT NULL,"transactionDate" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"reference" TEXT,"invoiceReference" TEXT,"amount" DECIMAL(12,2) NOT NULL,"paymentType" TEXT,"direction" "AccountTransactionDirection" NOT NULL,"description" TEXT,"createdBy" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AccountTransaction_pkey" PRIMARY KEY("id"));
ALTER TABLE "Payment" ADD COLUMN "paymentAccountId" TEXT;
CREATE UNIQUE INDEX "PaymentAccount_accountNumber_key" ON "PaymentAccount"("accountNumber");CREATE INDEX "AccountTransaction_transactionDate_idx" ON "AccountTransaction"("transactionDate");CREATE INDEX "AccountTransaction_accountId_idx" ON "AccountTransaction"("accountId");
ALTER TABLE "AccountTransaction" ADD CONSTRAINT "AccountTransaction_accountId_fkey" FOREIGN KEY("accountId") REFERENCES "PaymentAccount"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Payment" ADD CONSTRAINT "Payment_paymentAccountId_fkey" FOREIGN KEY("paymentAccountId") REFERENCES "PaymentAccount"("id") ON DELETE SET NULL ON UPDATE CASCADE;
